CREATE TABLE EK_TRANSACTION
(
	TRANSACTION_ID INT auto_increment,
	ORDER_ID INT  NOT NULL,
	CARD_ID INT NOT NULL,
	TOTAL_PRICE DECIMAL(12,2) NOT NULL,
	TRANSACTION_STATUS VARCHAR(50),
	TRANSACTION_DATE DATETIME NOT NULL,
	constraint EK_TRANSACTION_ID_PK primary key ( TRANSACTION_ID )
);

ALTER TABLE  EK_TRANSACTION ADD CONSTRAINT EK_TRANSACTION_STATUS_CK CHECK (TRANSACTION_STATUS in ('TRANSACTION_SUCCESS','TRANSACTION_FAILED'));

